// // This SR latch sets the output when S is low, resets the output when R is low, and holds the output when both S and R are high.
module sr_latch (
    input wire s,
    input wire r,
    input wire rst_n,
    output reg q
);

    always @(*) begin
        if (!rst_n) begin
            q <= 1'b0;
        end else if (s && !r) begin
            q <= 1'b1;
        end else if (!s && r) begin
            q <= 1'b0;
        end
    end

endmodule
